SimpleObjectPool={}function SimpleObjectPool:Init(a,b,c)local d={}setmetatable(d,self)self.__index=self;d.usingPool={}d.unusedPool={}d.instantiateFunc=a;d.compFunc=b;if c and c>0 then for e=1,c do table.insert(d.unusedPool,a())end end;return d end;function SimpleObjectPool:SpawnItem()local f;if#self.unusedPool<=0 then f=self.instantiateFunc()else f=table.remove(self.unusedPool)end;f.transform.gameObject:SetActive(true)table.insert(self.usingPool,f)return f end;function SimpleObjectPool:DespawnItem(f)if not f or Tools.IsArrayContains(self.usingPool,nil,function(d)return self.compFunc(d,f)end)then LogTool.Warning("SimpleObjectPool","尝试回收一个不存在的对象！")return end;local g=Tools.FindInArray(self.usingPool,nil,function(d)return self.compFunc(d,f)end)if g<1 then LogTool.Warning("SimpleObjectPool","尝试回收一个未受对象池管理的对象！")return end;f.transform.gameObject:SetActive(false)table.remove(self.usingPool,g)table.insert(self.unusedPool,f)end;function SimpleObjectPool:DespawnItemByIndex(g)if not g or g<1 or g>#self.usingPool then LogTool.Warning("SimpleObjectPool","尝试回收的对象的下标非法！Index: ",g)return end;local f=table.remove(self.usingPool,g)f.transform.gameObject:SetActive(false)table.insert(self.unusedPool,f)end;function SimpleObjectPool:DespawnAll()for e=1,#self.usingPool do local f=table.remove(self.usingPool)f.transform.gameObject:SetActive(false)table.insert(self.unusedPool,f)end end;return SimpleObjectPool